import { HeaderPage, Tabs, DocumentationForm } from "Components/Appraisal";

const tabs = [
	{
		title : "Documentación",
		Tab   : DocumentationForm,
	},
];

const AppraisalDoc = ({
	delegations : {
		onSubmit,
		hookForm,
		isLoading,
	},
}) => {

	const { formState : { isDirty } } = hookForm;

	return (
		<>
			<HeaderPage
				currentIndex={0}
				section="header"
				isDirty={isDirty}
				onSubmit={onSubmit}
				isSubmitingData={isLoading}
			/>
			<Tabs
				tabs={tabs}
				onSubmit={onSubmit}
				hookForm={hookForm}
				isSubmitingData={isLoading}
			/>
		</>
	);
};

export default AppraisalDoc;
