import { useEffect, useState }   from "react";
import { useForm, useFormState } from "react-hook-form";
import { useDispatch }           from "react-redux";
import { useParams }             from "react-router-dom";

import { getTime }                                 from "Helpers";
import { useHandlerMutation, useSendFileWithDesc } from "Helpers/Hooks";
import { FilesSlice }                              from "Store/Slices";
import { AppraisalHOCPageFetcher }                 from "Components/Appraisal";
import AppraisalDoc                                from "./AppraisalDoc";
import { DEFAULT_FETCH_DATA, PARAMS }              from "./AppraisalDocContants";


const AppraisalDocContainer = ({ appraise = DEFAULT_FETCH_DATA }) => {

	const { id : appraiseId } = useParams();

	const [loadingFiles, setLoadingFiles] = useState(false);

	// ------------> redux <---------------
	const distpach = useDispatch();

	// ------------> RTK-Q <---------------
	const [ editApprasial, { isLoading  : isLoadingMutation } ] = useHandlerMutation({ toastName : "apprasialCRUD" });

	const { documentation } = appraise;

	const {
		deed,
		plane,
		property_tax_bill,
		water_bill,
		other_files,
	} = documentation;

	// ------------> useHookForm <---------------
	const getFile = (fileInfo) => {
		if (!fileInfo?.location) {
			return null;
		}
		const file = { ...fileInfo };
		delete file?.description;

		return file;
	};

	const defaultValues  = {
		visit_date : getTime(documentation?.visit_date),
		deed       : {
			file        : getFile(deed),
			description : deed?.description ?? "",
		},

		plane : {
			file        : getFile(plane),
			description : plane?.description ?? "",
		},

		property_tax_bill : {
			file        : getFile(property_tax_bill),
			description : property_tax_bill?.description ?? "",
		},

		water_bill : {
			file        : getFile(water_bill),
			description : water_bill?.description ?? "",
		},

		other_files : other_files,
	};

	const hookForm = useForm({ defaultValues });

	const { handleSubmit, control } = hookForm;

	const { dirtyFields } = useFormState({ control });

	// ------------> submitData <---------------
	const submitDataWithOutFiles = async (visit_date) => {
		if (!dirtyFields?.visit_date) {
			return;
		}

		await editApprasial({
			module : `/appraisals/documentation/${appraiseId}`,
			method : "PUT",
			data   : { visit_date : visit_date[0] },
			tags   : ["appraisals", "apprasial_details"],
		});
	};

	const isDirtyFiles = () => {
		const isDirtySomeFile = dirtyFields?.deed?.file
		|| dirtyFields?.other_files
		|| dirtyFields?.plane?.file
		|| dirtyFields?.property_tax_bill?.file
		|| dirtyFields?.water_bill?.file;

		return isDirtySomeFile;
	};

	const isDirtyDescFiles = () => {
		const isDirtySomeDesc = dirtyFields?.deed?.description
		|| dirtyFields?.plane?.description
		|| dirtyFields?.property_tax_bill?.description
		|| dirtyFields?.water_bill?.description;

		return isDirtySomeDesc;
	};

	const [ handleSubmitFiles, handleRemoveFiles ] = useSendFileWithDesc({ dirtyFields, module : "atachment-file" });

	const submitFiles = async (files) => {
		if (!isDirtyFiles() && !isDirtyDescFiles()) {
			return;
		}
		await handleRemoveFiles();

		await handleSubmitFiles(files);
	};

	const onSubmit = handleSubmit(async (data) => {
		const { visit_date, ...filesFormData } = data;

		setLoadingFiles(true);

		await submitDataWithOutFiles(visit_date);

		await submitFiles(filesFormData);

		setLoadingFiles(false);
	});

	useEffect(() => {
		return () => {
			distpach(FilesSlice.actions.clearFiles());
		};
	}, []);

	return (
		<AppraisalDoc
			delegations={{
				onSubmit,
				hookForm,
				isLoading : isLoadingMutation || loadingFiles,
			}}
		/>
	);
};

export default AppraisalHOCPageFetcher(AppraisalDocContainer, PARAMS);
